import { scope } from "arktype";

// A directory tree node is:
//   - always has `name`: non-empty string
//   - if it's a FILE: has `size` (positive integer), must NOT have `children`
//   - if it's a DIRECTORY: has `children` (array of nodes), must NOT have `size`
//   - both fields are optional simultaneously only in that the node chooses one branch

const trees = scope({
  fileNode: {
    name: "string > 0",
    size: "integer > 0",
  },
  directoryNode: {
    name: "string > 0",
    "size?": "never",
    "children?": "treeNode[]",
  },
  treeNode: "fileNode | directoryNode",
});

export const { treeNode, fileNode, directoryNode } = trees.export();

export type TreeNode = typeof treeNode.infer;

/**
 * Validates the input as a directory tree node.
 * Returns the validated tree on success, or throws an ArkErrors instance on failure.
 */
export function validateDirectoryTree(input: unknown): TreeNode {
  return treeNode.assert(input);
}

import { validateDirectoryTree } from "./src/validator.js";

async function main(): Promise<void> {
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  const raw = Buffer.concat(chunks).toString("utf8").trim();

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    process.stdout.write("INVALID: input is not valid JSON\n");
    process.exit(0);
  }

  try {
    const result = validateDirectoryTree(parsed);
    process.stdout.write("VALID\n");
    process.stdout.write(JSON.stringify(result) + "\n");
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    process.stdout.write(`INVALID: ${message}\n`);
  }

  process.exit(0);
}

main();

